// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Sub-component: TaskCard for individual task display and editing
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  columns: Array<{ id?: string; name?: string }>;
  onMove: (taskId: string, targetColumn: string) => void;
  onEdit: (taskId: string, newTitle: string) => void;
  onDelete: (taskId: string) => void;
}

function TaskCard({ task, columns, onMove, onEdit, onDelete }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleSaveEdit = () => {
    if (editTitle.trim()) {
      onEdit(task.id || '', editTitle);
      setIsEditing(false);
    }
  };

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-500)';
      case 'medium':
        return 'var(--ggui-color-warning-500)';
      case 'low':
        return 'var(--ggui-color-success-500)';
      default:
        return 'var(--ggui-color-outline)';
    }
  };

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" style={{ cursor: 'grab', position: 'relative' }}>
      <Stack gap="var(--ggui-spacing-2)" align="start">
        {/* Task Title */}
        {isEditing ? (
          <Input
            label="Task title"
            value={editTitle}
            onChange={setEditTitle}
            onKeyDown={(e) => {
              if ((e as React.KeyboardEvent).key === 'Enter') handleSaveEdit();
              if ((e as React.KeyboardEvent).key === 'Escape') setIsEditing(false);
            }}
            autoFocus
          />
        ) : (
          <Text
            variant="body"
            weight="semibold"
            as={Clickable}
            onClick={() => setIsEditing(true)}
            style={{ cursor: 'pointer', width: '100%' }}
          >
            {task.title || 'Untitled'}
          </Text>
        )}

        {/* Priority Badge */}
        {task.priority && (
          <Badge
            variant={getPriorityVariant(task.priority)}
            size="sm"
            style={{ textTransform: 'capitalize' }}
          >
            {task.priority}
          </Badge>
        )}

        {/* Assignee Avatar */}
        {task.assignee && (
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Avatar
              name={task.assignee}
              size="sm"
              shape="circle"
            />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {task.assignee}
            </Text>
          </Row>
        )}

        {/* Due Date */}
        {task.dueDate && (
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            📅 {task.dueDate}
          </Text>
        )}

        {/* Action Buttons */}
        <Row gap="var(--ggui-spacing-1)" justify="between" style={{ width: '100%', marginTop: 'var(--ggui-spacing-2)' }}>
          {isEditing ? (
            <>
              <Button
                size="xs"
                variant="primary"
                onClick={handleSaveEdit}
              >
                Save
              </Button>
              <Button
                size="xs"
                variant="ghost"
                onClick={() => setIsEditing(false)}
              >
                Cancel
              </Button>
            </>
          ) : (
            <>
              <Dropdown
                trigger={
                  <Button size="xs" variant="ghost">
                    Move
                  </Button>
                }
                options={columns
                  .filter((col) => col.id !== task.column)
                  .map((col) => ({
                    value: col.id || '',
                    label: col.name || 'Unknown',
                  }))}
                value=""
                onChange={(targetColumn) => {
                  onMove(task.id || '', targetColumn);
                  setShowMoveMenu(false);
                }}
              />
              <Button
                size="xs"
                variant="ghost"
                onClick={() => onDelete(task.id || '')}
              >
                Delete
              </Button>
            </>
          )}
        </Row>
      </Stack>
    </Card>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for tasks and new task form
  const [tasks, setTasks] = useState(props.tasks || []);
  const [newTaskForm, setNewTaskForm] = useState<{ [key: string]: { title: string; priority: 'low' | 'medium' | 'high' } }>({});

  // Update local tasks when props change or stream updates arrive
  useEffect(() => {
    if (taskChanged.latest?.task) {
      setTasks((prevTasks) => {
        const taskId = taskChanged.latest?.task?.id;
        const action = taskChanged.latest?.action;

        if (action === 'delete') {
          return prevTasks.filter((t) => t.id !== taskId);
        } else if (action === 'create' || action === 'move' || action === 'edit') {
          const existingIndex = prevTasks.findIndex((t) => t.id === taskId);
          if (existingIndex >= 0) {
            const updated = [...prevTasks];
            updated[existingIndex] = taskChanged.latest.task;
            return updated;
          } else {
            return [...prevTasks, taskChanged.latest.task];
          }
        }
        return prevTasks;
      });
    }
  }, [taskChanged.latest]);

  // Handle task move between columns
  const handleMoveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setTasks((prevTasks) =>
        prevTasks.map((t) =>
          t.id === taskId ? { ...t, column: targetColumn } : t
        )
      );
      taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    },
    [taskUpdate]
  );

  // Handle task edit (title change)
  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setTasks((prevTasks) =>
        prevTasks.map((t) =>
          t.id === taskId ? { ...t, title: newTitle } : t
        )
      );
      taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
    },
    [taskUpdate, tasks]
  );

  // Handle task delete
  const handleDeleteTask = useCallback(
    (taskId: string) => {
      setTasks((prevTasks) => prevTasks.filter((t) => t.id !== taskId));
      taskUpdate({ action: 'delete', taskId, data: { column: '' } });
    },
    [taskUpdate]
  );

  // Handle create new task
  const handleCreateTask = useCallback(
    (columnId: string) => {
      const form = newTaskForm[columnId];
      if (form?.title?.trim()) {
        const newTask = {
          id: `task-${Date.now()}`,
          title: form.title,
          priority: form.priority,
          column: columnId,
          assignee: '',
          dueDate: '',
        };
        setTasks((prevTasks) => [...prevTasks, newTask]);
        taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
        setNewTaskForm((prev) => ({ ...prev, [columnId]: { title: '', priority: 'low' } }));
      }
    },
    [newTaskForm, taskUpdate]
  );

  // Calculate summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: { [key: string]: typeof tasks } = {};
    props.columns?.forEach((col) => {
      grouped[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with Summary */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={1}>Kanban Board</Heading>
          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
            <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
              <Text variant="body" color="var(--ggui-color-primary-900)">
                <Text variant="label" weight="bold" is="span" color="var(--ggui-color-primary-900)">
                  {totalTasks}
                </Text>{' '}
                total tasks
              </Text>
              <Text variant="body" color="var(--ggui-color-success-700)">
                <Text variant="label" weight="bold" is="span" color="var(--ggui-color-success-700)">
                  {completedTasks}
                </Text>{' '}
                completed
              </Text>
              <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} variant="success" size="sm" />
            </Row>
          </Box>
        </Stack>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" style={{ overflowX: 'auto' }}>
          {props.columns?.map((column) => {
            const columnTasks = tasksByColumn[column.id || ''] || [];
            const form = newTaskForm[column.id || ''] || { title: '', priority: 'low' };

            return (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                radius="lg"
                style={{ minWidth: '300px', flexShrink: 0, background: 'var(--ggui-color-surfaceVariant)' }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column Header */}
                  <Box>
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Heading level={3} color="var(--ggui-color-onSurfaceVariant)">
                        {column.name}
                      </Heading>
                      <Badge variant="default" size="sm">
                        {columnTasks.length}
                      </Badge>
                    </Row>
                  </Box>

                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                  {/* Task List */}
                  <Stack gap="var(--ggui-spacing-3)" align="stretch">
                    {columnTasks.map((task) => (
                      <TaskCard
                        key={task.id}
                        task={task}
                        columns={props.columns || []}
                        onMove={handleMoveTask}
                        onEdit={handleEditTask}
                        onDelete={handleDeleteTask}
                      />
                    ))}
                  </Stack>

                  {/* Add Task Form */}
                  <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surface)" borderRadius="var(--ggui-shape-radius-md)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input
                        label="Task title"
                        placeholder="Add a new task..."
                        value={form.title}
                        onChange={(value) =>
                          setNewTaskForm((prev) => ({
                            ...prev,
                            [column.id || '']: { ...form, title: value },
                          }))
                        }
                      />
                      <Select
                        label="Priority"
                        value={form.priority}
                        onChange={(value) =>
                          setNewTaskForm((prev) => ({
                            ...prev,
                            [column.id || '']: { ...form, priority: value as 'low' | 'medium' | 'high' },
                          }))
                        }
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Button
                        variant="primary"
                        size="sm"
                        fullWidth
                        onClick={() => handleCreateTask(column.id || '')}
                      >
                        Add Task
                      </Button>
                    </Stack>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
